def is_prime(n):
    if n <= 1:
        return False
    i = 2
    while i * i <= n:
        if n % i == 0:
            return False
        i += 1
    return True

def closest_prime_pair(left, right):
    min_dist = right - left + 1
    ans = [-1, -1]
    for i in range(left, right + 1):
        if is_prime(i):
            for j in range(i + 1, right + 1):
                if is_prime(j) and j - i < min_dist:
                    min_dist = j - i
                    ans = [i, j]
    return ans
